INSERT INTO region (city, district, dong) VALUES ('서울특별시', '강남구', '역삼1동');
INSERT INTO disposal_schedule (category, disposal_day, disposal_time, region_id) VALUES
    ('PLASTIC', '화요일, 금요일', '해진 후 ~ 자정(24:00)', @r5),
    ('PAPER', '월요일, 목요일', '해진 후 ~ 자정(24:00)', @r5),
    ('STEEL', '수요일', '해진 후 ~ 자정(24:00)', @r5),
    ('GLASS', '수요일', '해진 후 ~ 자정(24:00)', @r5),
    ('FOOD', '월요일~토요일 (매일)', '해진 후 ~ 자정(24:00)', @r5),
    ('GENERAL', '화요일, 목요일, 토요일', '해진 후 ~ 자정(24:00)', @r5),
    ('WRAP', '화요일, 금요일', '해진 후 ~ 자정(24:00)', @r5),
    ('STYROFOAM', '목요일', '해진 후 ~ 자정(24:00)', @r5);
INSERT INTO trash_detail (region_id, category, item_name, disposal_method, pre_treatment, caution) VALUES
    (@r5, 'PLASTIC', '페트병 / 플라스틱 용기', '1단계. 내용물을 완전히 비우기\n2단계. 흐르는 물로 가볍게 헹구기\n3단계. 라벨 완전히 제거\n4단계. 압착하여 부피 줄이기\n5단계. 투명봉투에 담아 지정 요일 배출', '내용물 비우기 · 세척 · 라벨 제거 · 압착', '라벨 미제거·이물질 있는 용기는 일반쓰레기. 무색 투명 페트병(생수·음료)은 라벨을 떼고 내용물을 비운 뒤 압착 후 뚜껑을 닫아 별도로 분리배출(2020년~ 의무화)'),
    (@r5, 'PAPER', '종이류 (신문지 / 잡지 / 박스)', '1단계. 박스는 테이프·스테이플러 제거 후 납작하게 접기\n2단계. 신문지·잡지는 가지런히 쌓기\n3단계. 물기 및 이물질 제거\n4단계. 끈으로 묶거나 박스에 담기\n5단계. 지정 요일 배출', '테이프·스테이플러 제거, 물기 제거', '코팅지·영수증(감열지)·사진은 일반쓰레기. 우유팩·두유팩 등 종이팩은 일반 종이류와 섞지 말고 헹궈 말린 뒤 종이팩 전용수거함에 별도 배출'),
    (@r5, 'STEEL', '캔류 (음료캔 / 통조림캔)', '1단계. 내용물을 완전히 비우기\n2단계. 흐르는 물로 헹구기\n3단계. 압착하여 부피 줄이기\n4단계. 투명봉투에 담아 지정 요일 배출', '내용물 비우기 · 헹구기 · 압착', '부탄가스·스프레이 캔은 야외에서 노즐을 눌러 잔여가스를 완전히 제거 후 배출(송곳·못으로 구멍 뚫기 금지, 폭발 위험). 뚜껑은 분리'),
    (@r5, 'GLASS', '유리병류 (소주병 / 맥주병 / 음료수병)', '1단계. 내용물을 완전히 비우기\n2단계. 뚜껑(금속·플라스틱) 분리\n3단계. 라벨 제거\n4단계. 흐르는 물로 세척\n5단계. 투명봉투에 담아 지정 요일 배출', '뚜껑 분리 · 라벨 제거 · 세척', '깨진 유리는 신문지에 싸서 "깨진유리" 표시 후 일반쓰레기. 도자기·사기·내열유리·거울은 일반쓰레기. 형광등은 전용수거함'),
    (@r5, 'FOOD', '음식물 쓰레기', '1단계. 이물질(이쑤시개·젓가락 등) 완전히 제거\n2단계. 수분(물기) 최대한 짜내기\n3단계. 음식물 전용봉투 또는 RFID·칩 방식 용기에 담기\n4단계. 지정 시간 배출 (매일)', '수분(물기) 최대한 제거 필수', '뼈·조개껍데기·계란껍데기·견과류껍질·고추씨·복어내장은 일반쓰레기. 이쑤시개·일회용품 혼입 금지'),
    (@r5, 'GENERAL', '일반쓰레기', '1단계. 재활용품·음식물과 완전히 분리\n2단계. 종량제봉투(소각용)에 담기\n3단계. 지정 요일 배출', '재활용·음식물과 반드시 분리', '재활용 가능 품목을 일반쓰레기에 섞어 배출 시 과태료 부과. 종량제봉투 미사용 배출 금지'),
    (@r5, 'WRAP', '비닐류 (봉투 / 랩 / 뽁뽁이)', '1단계. 내용물·이물질 완전히 제거\n2단계. 흐르는 물로 세척\n3단계. 완전히 건조\n4단계. 투명봉투에 담아 지정 요일 배출', '이물질 제거 및 세척 후 건조', '오염이 심해 세척 불가 시 일반쓰레기. 뽁뽁이(에어캡)는 비닐로 배출 가능. 검은색·유색 봉투는 배출 불가'),
    (@r5, 'STYROFOAM', '스티로폼 (포장재 / 컵)', '1단계. 테이프·스티커·이물질 완전히 제거\n2단계. 납작하게 압착하여 부피 줄이기\n3단계. 끈으로 묶거나 별도 봉투에 담기\n4단계. 지정 요일 배출', '테이프 · 이물질 완전 제거 후 압착', '이물질 제거 안 된 것·색상 스티로폼은 일반쓰레기. 컵라면 용기는 깨끗이 세척한 경우만 재활용, 기름·양념 오염 시 일반쓰레기');
INSERT INTO region (city, district, dong) VALUES ('서울특별시', '서초구', '서초2동');
