-- ============================================================
-- RecycleMap Phase 9 EC2 마이그레이션 (seed_data.sql 에서 자동 생성)
-- 1) 수원 caution 정정  2) cruft region 정리  3) 서울 5구 auto-id 삽입
-- 실행: docker exec -i recycle-db mysql -uroot -p... --default-character-set=utf8mb4 recycle_db < 이파일
-- ============================================================

START TRANSACTION;

-- [1] 수원 caution 정정 (투명페트병/종이팩/컵라면)
UPDATE trash_detail SET caution = '라벨 제거 안 된 것, 이물질 있는 것은 일반쓰레기 처리. 기름때 심한 용기도 일반쓰레기. 무색 투명 페트병(생수·음료)은 라벨을 떼고 내용물을 비운 뒤 압착 후 뚜껑을 닫아 별도로 분리배출(2020년~ 의무화)' WHERE region_id = 1 AND category = 'PLASTIC';
UPDATE trash_detail SET caution = '음식물 묻은 종이·코팅지·사진·영수증(감열지)·금은박지는 일반쓰레기. 우유팩·두유팩 등 종이팩은 일반 종이류와 섞지 말고 헹궈 말린 뒤 종이팩 전용수거함에 별도 배출' WHERE region_id = 1 AND category = 'PAPER';
UPDATE trash_detail SET caution = '이물질(테이프 등) 제거 안 된 것은 일반쓰레기. 색이 들어간 스티로폼은 일반쓰레기' WHERE region_id = 1 AND category = 'STYROFOAM';
UPDATE trash_detail SET caution = '라벨 미제거, 기름때 심한 용기는 일반쓰레기. PVC 재질은 재활용 불가. 무색 투명 페트병(생수·음료)은 라벨을 떼고 내용물을 비운 뒤 압착 후 뚜껑을 닫아 별도로 분리배출(2020년~ 의무화)' WHERE region_id = 2 AND category = 'PLASTIC';
UPDATE trash_detail SET caution = '코팅된 종이·영수증(감열지)·사진은 일반쓰레기. 음식물 오염 심한 것도 일반쓰레기. 우유팩·두유팩 등 종이팩은 일반 종이류와 섞지 말고 헹궈 말린 뒤 종이팩 전용수거함에 별도 배출' WHERE region_id = 2 AND category = 'PAPER';
UPDATE trash_detail SET caution = '이물질 잔존 시 일반쓰레기 처리. 스티로폼 컵(라면 용기)은 깨끗이 세척한 경우만 재활용, 기름·양념 오염 시 일반쓰레기' WHERE region_id = 2 AND category = 'STYROFOAM';
UPDATE trash_detail SET caution = '세제·샴푸 용기도 세척 후 배출 가능. 장난감·칫솔 등 혼합재질 플라스틱은 일반쓰레기. 무색 투명 페트병(생수·음료)은 라벨을 떼고 내용물을 비운 뒤 압착 후 뚜껑을 닫아 별도로 분리배출(2020년~ 의무화)' WHERE region_id = 3 AND category = 'PLASTIC';
UPDATE trash_detail SET caution = '코팅지·감열지·금은박지·부직포는 일반쓰레기. 우유팩·두유팩 등 종이팩은 일반 종이류와 섞지 말고 헹궈 말린 뒤 종이팩 전용수거함에 별도 배출' WHERE region_id = 3 AND category = 'PAPER';
UPDATE trash_detail SET caution = '색상 있는 스티로폼·이물질 제거 불가 시 일반쓰레기' WHERE region_id = 3 AND category = 'STYROFOAM';
UPDATE trash_detail SET caution = '라벨 미제거·이물질 있으면 일반쓰레기. 무색 투명 페트병(생수·음료)은 라벨을 떼고 내용물을 비운 뒤 압착 후 뚜껑을 닫아 별도로 분리배출(2020년~ 의무화)' WHERE region_id = 4 AND category = 'PLASTIC';
UPDATE trash_detail SET caution = '코팅지·영수증(감열지)·사진·택배 송장(비닐 포함)은 일반쓰레기. 우유팩·두유팩 등 종이팩은 일반 종이류와 섞지 말고 헹궈 말린 뒤 종이팩 전용수거함에 별도 배출' WHERE region_id = 4 AND category = 'PAPER';
UPDATE trash_detail SET caution = '이물질 제거 불가·색상 스티로폼은 일반쓰레기. 스티로폼 컵라면 용기는 깨끗이 세척한 경우만 재활용, 오염 시 일반쓰레기' WHERE region_id = 4 AND category = 'STYROFOAM';

-- [2] cruft region(동=NULL) 정리: 참조 user 재지정 후 삭제
--   수원시 같은 구의 정상 region(동 NOT NULL)으로 user 이전
UPDATE user u JOIN region c ON u.region_id = c.region_id AND c.dong IS NULL
  JOIN region g ON g.city = c.city AND g.district = c.district AND g.dong IS NOT NULL
  SET u.region_id = g.region_id;
DELETE FROM region WHERE dong IS NULL;

-- [3] 서울 5구 삽입 (auto-id, @rN 변수로 자식행 연결)
-- 강남구 역삼1동
SET @r5 := LAST_INSERT_ID();

-- 서초구 서초2동
SET @r6 := LAST_INSERT_ID();

-- 송파구 잠실본동
SET @r7 := LAST_INSERT_ID();

-- 마포구 서교동
SET @r8 := LAST_INSERT_ID();

-- 용산구 이태원1동
SET @r9 := LAST_INSERT_ID();

COMMIT;

-- 검증
SELECT region_id, city, district, dong FROM region ORDER BY region_id;
SELECT region_id, COUNT(*) FROM trash_detail GROUP BY region_id ORDER BY region_id;
SELECT region_id, COUNT(*) FROM disposal_schedule GROUP BY region_id ORDER BY region_id;